+void Turtlebot4Hmi::OnPowerLedMessage(const ignition::msgs::Int32 &msg)
+{
+
+  switch(msg.data())
+  {
+    case 0:
+    {
+      emit setPowerState(false, "green");
+      break;
+    }
+
+    case 1:
+    {
+      emit setPowerState(true, "green");
+      break;
+    }
+
+    default:
+      break;
+  }
+}
